Here's a modern MSTest approach using a fake `HttpMessageHandler` to control responses, with proper cancellation/timeout patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, FakeHandler handler) CreateFetcher(
        HttpStatusCode status = HttpStatusCode.OK,
        string content = "")
    {
        var handler = new FakeHandler(status, content);
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.OK, "hello");

        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.NotFound);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceledException()
    {
        using var cts = CancellationTokenSource.CreateLinkedTokenSource(
            _testContext.CancellationToken);
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        cts.Cancel();

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(2000)] // test-level timeout — triggers CancellationToken
    public async Task FetchAsync_SlowResponse_TimeoutCancelsFetch()
    {
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // TestContext.CancellationToken fires when [Timeout] expires
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    // Minimal fake handler — no mocking library needed
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpStatusCode _status;
        private readonly string _content;
        private readonly TimeSpan _delay;

        public FakeHandler(
            HttpStatusCode status = HttpStatusCode.OK,
            string content = "",
            TimeSpan delay = default)
        {
            _status = status;
            _content = content;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_status)
            {
                Content = new StringContent(_content),
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `TestContext.CancellationToken` | Cooperates with `[Timeout]` — MSTest cancels the token when time expires |
| `CreateLinkedTokenSource` | Lets you cancel explicitly *while* still respecting the test timeout |
| `Assert.ThrowsExactlyAsync` | Verifies the exact exception type (not `[ExpectedException]`) |
| `FakeHandler` | Subclass `HttpMessageHandler` directly — no mocking library needed for `HttpClient` |
| `sealed` test class | MSTest best practice for performance |
| Constructor-injected `TestContext` | Enables `readonly` field, works with nullability |

The critical insight: **always flow `TestContext.CancellationToken`** (or a linked token) into your async calls. This is what makes `[Timeout]` actually cancel work instead of just failing the test after the fact.
